import{_ as a,c as i,o as e,aj as s,b2 as l,b3 as r,b4 as d,b5 as n,b6 as h,b7 as o}from"./chunks/framework.CoirRWyn.js";const I=JSON.parse('{"title":"2.4 用AI推理 [Reasoning with AI]","description":"","frontmatter":{},"headers":[],"relativePath":"module_2/2.4用AI推理[Reasoning with AI].md","filePath":"module_2/2.4用AI推理[Reasoning with AI].md"}'),p={name:"module_2/2.4用AI推理[Reasoning with AI].md"};function c(b,t,g,_,k,m){return e(),i("div",null,[...t[0]||(t[0]=[s('<h1 id="_2-4-用ai推理-reasoning-with-ai" tabindex="-1">2.4 用AI推理 [Reasoning with AI] <a class="header-anchor" href="#_2-4-用ai推理-reasoning-with-ai" aria-label="Permalink to “2.4 用AI推理 [Reasoning with AI]”">​</a></h1><blockquote><p><strong>主题：</strong> 在复杂问题中让 AI 进行更深入的分析，而不是只给表层回答。</p></blockquote><p>AI 不只可以回答事实性问题，也可以帮助处理需要多步骤分析的复杂任务。例如比较多个选择、评估方案优劣、规划项目路线、分析风险、构建决策标准等。</p><p><img src="'+l+'" alt="alt text"></p><p>复杂任务通常没有唯一答案。比如比较保险计划、贷款报价或旅游路线，AI 不能只看表面信息，而要读取资料、比较条件、分析权衡，再给出建议。</p><p><img src="'+r+'" alt="alt text"></p><p>AI 在长任务能力上的进步，使它可以承担更复杂的工作，例如审查文档、写长文、分析漏洞、整理大量信息等。任务越复杂，越不能只要求它快速回答，而要让它认真检查约束和证据。</p><p><img src="'+d+'" alt="alt text"></p><p>对于需要长时间分析、复杂推理和多步骤规划的任务，应尽量使用能力较强、较新的模型。较弱模型可能能回答简单问题，但在长文理解、复杂约束和工具使用上更容易出错。</p><p><img src="'+n+'" alt="alt text"></p><p>AI 推理通常包括：理解目标、读取上下文、拆解问题、制定计划、必要时调用工具、检查约束、给出最终答案。例如规划罗马一日游路线时，AI 需要估算路程、查询开放时间、安排顺序并输出可执行行程。</p><p><img src="'+h+'" alt="alt text"></p><p>让 AI 推理不是简单写一句“逐步思考”，而是要明确要求它建立标准、比较方案、指出风险和不确定性。比如可以要求：“不要急着给结论，先列判断标准，再比较备选方案。”</p><p><img src="'+o+'" alt="alt text"></p><p>使用 AI 推理的经验法则包括：使用能力较强的模型、提供足够上下文、给模型真实且有难度的任务，并明确要求它深入分析。</p><h2 id="ai-推理通常包含哪些步骤" tabindex="-1">AI 推理通常包含哪些步骤 <a class="header-anchor" href="#ai-推理通常包含哪些步骤" aria-label="Permalink to “AI 推理通常包含哪些步骤”">​</a></h2><ol><li>理解任务目标；</li><li>读取上下文和材料；</li><li>拆解问题；</li><li>建立评价标准；</li><li>比较备选方案；</li><li>必要时调用工具；</li><li>检查限制条件；</li><li>给出最终建议；</li><li>标注假设、不确定性和风险。</li></ol><h2 id="什么时候适合让-ai-深度推理" tabindex="-1">什么时候适合让 AI 深度推理 <a class="header-anchor" href="#什么时候适合让-ai-深度推理" aria-label="Permalink to “什么时候适合让 AI 深度推理”">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>是否适合深度推理</th><th>原因</th></tr></thead><tbody><tr><td>问一个简单概念</td><td>不一定需要</td><td>直接解释即可</td></tr><tr><td>比较多个方案</td><td>适合</td><td>需要建立标准并权衡</td></tr><tr><td>制定项目路线</td><td>适合</td><td>涉及步骤、资源和风险</td></tr><tr><td>写长篇论文或报告</td><td>适合</td><td>需要结构、逻辑和证据</td></tr><tr><td>做高风险决策</td><td>适合，但需人工复核</td><td>可能涉及法律、财务、医疗等风险</td></tr></tbody></table><h2 id="可直接套用的-prompt-模板" tabindex="-1">可直接套用的 Prompt 模板 <a class="header-anchor" href="#可直接套用的-prompt-模板" aria-label="Permalink to “可直接套用的 Prompt 模板”">​</a></h2><h3 id="模板-1-方案比较" tabindex="-1">模板 1：方案比较 <a class="header-anchor" href="#模板-1-方案比较" aria-label="Permalink to “模板 1：方案比较”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>我需要在以下方案中做选择：【方案 A】【方案 B】【方案 C】。请先建立评价标准，再逐项比较每个方案的优点、缺点、成本、风险和适用场景，最后给出推荐结论。</span></span></code></pre></div><h3 id="模板-2-复杂问题分析" tabindex="-1">模板 2：复杂问题分析 <a class="header-anchor" href="#模板-2-复杂问题分析" aria-label="Permalink to “模板 2：复杂问题分析”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>请认真分析以下问题。不要直接给结论，请先拆解问题、列出关键假设、说明需要考虑的因素，再给出可执行建议。对不确定内容请单独标注。</span></span></code></pre></div><h3 id="模板-3-风险审查" tabindex="-1">模板 3：风险审查 <a class="header-anchor" href="#模板-3-风险审查" aria-label="Permalink to “模板 3：风险审查”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>请从风险角度审查这个计划。请指出可能失败的原因、被忽略的前提、执行中的难点，以及可以提前准备的备选方案。</span></span></code></pre></div><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h2><p>AI 推理的重点不是回答更长，而是回答前真的进行比较、验证和取舍。复杂问题要让 AI 做过程，而不是只要结果。对于重要任务，应该要求 AI 写出假设、证据和不确定性，方便用户判断哪些结论可信。</p><hr>',29)])])}const x=a(p,[["render",c]]);export{I as __pageData,x as default};
